VALUES
  ('social-worker-moex-01591', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '對於障礙者就業觀點，下列何者屬於社會模式的障礙觀點？①障礙是身體或心智損傷對個人身心', '["障礙的形成是社會與政治的建構過程，要降低身體損傷所造成的不利影 響，需改變社會結構與制度", "要排除就業障礙，需要透過持續醫療、復健、矯治或照顧", "必 須建構融合、多元及具有支持性的就業環境", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01592', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '政府結合民間團體提供適合場所，提供中輟生輔導資源與中介教育措施，每班以8～15人為限， 學生仍在社區環境中，可以提供更多社福資源，以協助學生問題的處理。這屬於下列何種中介教 育模式？', '["慈暉班", "高關懷班", "資源式中途班", "合作式中途班"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01593', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列有關職業社會工作（Occupational Social Work）的敘述何者錯誤？', '["主要功能在協助提升員工的工作效能、增強組織結構及資源管理，以及研擬多元創新之福利服 務方案", "在早期發展階段時的主要服務對象是工廠員工", "有法定責任推動組成工會保障權益", "員工協助方案（Employee Assistant Program，EAP）是常見的服務模式"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01594', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '依據美國社會工作人員協會（NASW）（2013），已將醫務社會工作修訂正名，並定義其為在公 共衛生或急/慢性醫療照護場域，提供包括健康教育、危機處遇、支持性諮商與個案管理等專業 服務。下列何者為其修訂名稱？', '["醫院社會工作（Hospital Social Work）", "健康照護社會工作（Social Work Practice in Health Care Settings）", "臨床社會工作（Clinical Social Work）", "健康社會工作（Health Social Work）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01595', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '當前全球政治經濟局勢與極端氣候變遷下，從災變的發生到災後重建的過程中，社會工作者的角 色任務不包括下列何者？', '["探勘潛在的災變發生源頭與再發率", "整合管理與輸送人力與物質資源", "建構能對抗災變的社區復原力保護因子", "提供社會心理傷害之處遇與危機干預"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01596', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '有關社會教育學（social pedagogy，或譯為社會教導模式）理論假設的敘述，下列何者正確？', '["主張應讓弱勢者都能進入正式教育體制", "主張學習是個人生活的一部分，而學習不能脫離生活情境與社會脈絡", "主張個人的非理性認知需要被教育", "主張要建立有明確階層的師徒關係"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "66c93ebbd30f", "answer_pdf_sha1": "f25cffed70b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01597', 'social-worker', 'social-worker-moex-108-694fe135', 'sub-social-worker-03', NULL, 'essay', '依照實務經驗，需接受兒少保護強制親職教育的父母、監護人或實際照
顧者，經常都是「非自願案主」。假如你是一位兒少保護社會工作者，
請說明上述「非自願案主」有那些行為特徵？與「非自願案主」工作的
